def match_refinery_regions(text: str) -> list[dict[str, str]]:
    source = text or ""
    matches: list[dict[str, str]] = []
    seen: set[tuple[str, str]] = set()
    for row in REFINERY_REGION_ROWS:
        short_name = row.get("short_name") or ""
        full_name = row.get("full_name") or ""
        if (short_name and short_name in source) or (full_name and full_name in source):
            key = (row.get("region") or "", short_name or full_name)
            if key in seen:
                continue
            seen.add(key)
            matches.append(row)
    return matches


def matched_region_names(text: str) -> list[str]:
    regions: list[str] = []
    for row in match_refinery_regions(text):
        region = row.get("region") or ""
        if region and region not in regions:
            regions.append(region)
    return regions
